import{_ as n,o as t,c as i,a0 as o}from"./chunks/framework.jwovEGr5.js";const d=JSON.parse('{"title":"Sơ đồ Tài khoản","description":"","frontmatter":{"title":"Sơ đồ Tài khoản"},"headers":[],"relativePath":"chart-of-accounts.md","filePath":"chart-of-accounts.md"}'),a={name:"chart-of-accounts.md"};function c(r,h,l,e,g,u){return t(),i("div",null,[...h[0]||(h[0]=[o('<h1 id="so-đo-tai-khoan" tabindex="-1">Sơ đồ Tài khoản <a class="header-anchor" href="#so-đo-tai-khoan" aria-label="Permalink to &quot;Sơ đồ Tài khoản&quot;">​</a></h1><h2 id="gioi-thieu" tabindex="-1">Giới thiệu <a class="header-anchor" href="#gioi-thieu" aria-label="Permalink to &quot;Giới thiệu&quot;">​</a></h2><p>Sơ đồ Tài khoản (Chart of Accounts) là xương sống của hệ thống kế toán trong ABNERP. Đây là danh sách đầy đủ các tài khoản được sử dụng để ghi chép, phân loại và báo cáo các giao dịch tài chính của doanh nghiệp. Mỗi tài khoản đại diện cho một hạng mục cụ thể như tài sản, nợ phải trả, vốn chủ sở hữu, doanh thu hoặc chi phí.</p><h2 id="cau-truc-so-đo-tai-khoan" tabindex="-1">Cấu trúc Sơ đồ Tài khoản <a class="header-anchor" href="#cau-truc-so-đo-tai-khoan" aria-label="Permalink to &quot;Cấu trúc Sơ đồ Tài khoản&quot;">​</a></h2><p>Sơ đồ Tài khoản trong ABNERP được tổ chức theo cấu trúc phân cấp, bao gồm các nhóm và tài khoản con:</p><h3 id="cac-nhom-tai-khoan-chinh" tabindex="-1">Các nhóm tài khoản chính <a class="header-anchor" href="#cac-nhom-tai-khoan-chinh" aria-label="Permalink to &quot;Các nhóm tài khoản chính&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Nhóm</th><th>Mô tả</th><th>Ví dụ</th></tr></thead><tbody><tr><td>Tài sản (Assets)</td><td>Nguồn lực của doanh nghiệp</td><td>Tiền mặt, Phải thu khách hàng, Hàng tồn kho</td></tr><tr><td>Nợ phải trả (Liabilities)</td><td>Nghĩa vụ tài chính</td><td>Phải trả nhà cung cấp, Vay ngân hàng</td></tr><tr><td>Vốn chủ sở hữu (Equity)</td><td>Vốn và lợi nhuận giữ lại</td><td>Vốn góp, Lợi nhuận giữ lại</td></tr><tr><td>Doanh thu (Revenue)</td><td>Thu nhập từ hoạt động</td><td>Doanh thu bán hàng, Doanh thu dịch vụ</td></tr><tr><td>Chi phí (Expenses)</td><td>Chi phí hoạt động</td><td>Tiền lương, Tiền thuê nhà, Nguyên vật liệu</td></tr></tbody></table><h2 id="thiet-lap-so-đo-tai-khoan" tabindex="-1">Thiết lập Sơ đồ Tài khoản <a class="header-anchor" href="#thiet-lap-so-đo-tai-khoan" aria-label="Permalink to &quot;Thiết lập Sơ đồ Tài khoản&quot;">​</a></h2><h3 id="tao-moi-cong-ty" tabindex="-1">Tạo mới Công ty <a class="header-anchor" href="#tao-moi-cong-ty" aria-label="Permalink to &quot;Tạo mới Công ty&quot;">​</a></h3><p>Khi tạo một Công ty mới trong ABNERP, hệ thống tự động tạo Sơ đồ Tài khoản mặc định dựa trên quốc gia và ngành nghề của doanh nghiệp. Bạn có thể tùy chỉnh sơ đồ này sau đó.</p><h3 id="them-tai-khoan-moi" tabindex="-1">Thêm tài khoản mới <a class="header-anchor" href="#them-tai-khoan-moi" aria-label="Permalink to &quot;Thêm tài khoản mới&quot;">​</a></h3><ol><li>Truy cập: <strong>Kế toán &gt; Sơ đồ Tài khoản</strong></li><li>Nhấn <strong>Thêm tài khoản mới</strong></li><li>Nhập thông tin: <ul><li><strong>Mã tài khoản</strong>: Mã định danh duy nhất</li><li><strong>Tên tài khoản</strong>: Tên hiển thị</li><li><strong>Nhóm tài khoản cha</strong>: Chọn nhóm hoặc tài khoản cha</li><li><strong>Loại tài khoản</strong>: Xác định loại (Tài sản, Nợ, Vốn, Doanh thu, Chi phí)</li><li><strong>Báo cáo mặc định</strong>: Chọn báo cáo tài chính mà tài khoản này thuộc về</li></ul></li></ol><h3 id="chinh-sua-tai-khoan" tabindex="-1">Chỉnh sửa tài khoản <a class="header-anchor" href="#chinh-sua-tai-khoan" aria-label="Permalink to &quot;Chỉnh sửa tài khoản&quot;">​</a></h3><p>Bạn có thể chỉnh sửa tài khoản bất kỳ lúc nào. Lưu ý rằng việc thay đổi nhóm cha có thể ảnh hưởng đến báo cáo tài chính.</p><h3 id="vo-hieu-hoa-tai-khoan" tabindex="-1">Vô hiệu hóa tài khoản <a class="header-anchor" href="#vo-hieu-hoa-tai-khoan" aria-label="Permalink to &quot;Vô hiệu hóa tài khoản&quot;">​</a></h3><p>Tài khoản không còn sử dụng có thể bị vô hiệu hóa thay vì xóa để đảm bảo tính toàn vẹn của dữ liệu lịch sử.</p><h2 id="cac-tai-khoan-tieu-chuan" tabindex="-1">Các tài khoản tiêu chuẩn <a class="header-anchor" href="#cac-tai-khoan-tieu-chuan" aria-label="Permalink to &quot;Các tài khoản tiêu chuẩn&quot;">​</a></h2><p>ABNERP cung cấp Sơ đồ Tài khoản mặc định bao gồm:</p><ul><li><strong>1110 - Tiền mặt</strong>: Ghi nhận tiền mặt tại quỹ</li><li><strong>1120 - Tiền gửi ngân hàng</strong>: Tài khoản ngân hàng</li><li><strong>1310 - Phải thu khách hàng</strong>: Công nợ phải thu</li><li><strong>1560 - Hàng tồn kho</strong>: Giá trị hàng tồn kho</li><li><strong>2110 - Phải trả nhà cung cấp</strong>: Công nợ phải trả</li><li><strong>5110 - Doanh thu bán hàng</strong>: Doanh thu từ bán hàng hóa</li><li><strong>6210 - Giá vốn hàng bán</strong>: Chi phí hàng bán</li><li><strong>6410 - Chi phí bán hàng</strong>: Chi phí liên quan đến bán hàng</li></ul><h2 id="tich-hop-voi-cac-mo-đun-khac" tabindex="-1">Tích hợp với các mô-đun khác <a class="header-anchor" href="#tich-hop-voi-cac-mo-đun-khac" aria-label="Permalink to &quot;Tích hợp với các mô-đun khác&quot;">​</a></h2><p>Sơ đồ Tài khoản được liên kết với các mô-đun khác trong ABNERP:</p><ul><li><strong>Kho</strong>: Tài khoản hàng tồn kho mặc định cho từng mặt hàng</li><li><strong>Mua hàng</strong>: Tài khoản chi phí và công nợ phải trả</li><li><strong>Bán hàng</strong>: Tài khoản doanh thu và công nợ phải thu</li><li><strong>Nhân sự</strong>: Tài khoản lương và các khoản trích theo lương</li></ul><h2 id="meo-va-luu-y" tabindex="-1">Mẹo và lưu ý <a class="header-anchor" href="#meo-va-luu-y" aria-label="Permalink to &quot;Mẹo và lưu ý&quot;">​</a></h2><ul><li>Nên lập kế hoạch Sơ đồ Tài khoản trước khi triển khai</li><li>Không xóa tài khoản đã phát sinh giao dịch — hãy vô hiệu hóa thay thế</li><li>Sử dụng mã số tài khoản nhất quán để dễ dàng báo cáo hợp nhất</li><li>Tham khảo ý kiến kế toán viên hoặc chuyên gia thuế khi thiết lập</li></ul>',24)])])}const k=n(a,[["render",c]]);export{d as __pageData,k as default};
